using System.ClientModel;
using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration – set via environment variables
// ---------------------------------------------------------------------------
var modelName = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? "";
var endpoint = Environment.GetEnvironmentVariable("OPENAI_ENDPOINT"); // optional

if (string.IsNullOrWhiteSpace(apiKey))
{
    Console.Error.WriteLine("Error: set the OPENAI_API_KEY environment variable.");
    return 1;
}

// ---------------------------------------------------------------------------
// Build the AI chat client with tools
// ---------------------------------------------------------------------------
var openAIOptions = new OpenAIClientOptions();
if (!string.IsNullOrEmpty(endpoint))
    openAIOptions.Endpoint = new Uri(endpoint);

var openAIClient = new OpenAIClient(new ApiKeyCredential(apiKey), openAIOptions);

var notebook = new Notebook();

IChatClient chatClient = openAIClient
    .GetChatClient(modelName)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(WebSearchTool.SearchWeb),
    AIFunctionFactory.Create(WebSearchTool.FetchPage),
    AIFunctionFactory.Create(notebook.SaveNote),
    AIFunctionFactory.Create(notebook.GetNotes),
};

// ---------------------------------------------------------------------------
// Prompt the user for a research topic
// ---------------------------------------------------------------------------
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.Error.WriteLine("No topic provided.");
    return 1;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// ---------------------------------------------------------------------------
// Run the agent loop
// ---------------------------------------------------------------------------
var systemPrompt = $"""
    You are a research agent. Your goal is to thoroughly research the following topic
    and produce a well-structured summary.

    **Topic:** {topic}

    Instructions:
    1. Use the SearchWeb tool to find relevant information. Run multiple searches with
       different queries to get broad coverage.
    2. Use the FetchPage tool to read promising pages in detail.
    3. Use the SaveNote tool to record key facts, statistics, and quotes as you go.
    4. After gathering enough information, use GetNotes to review everything you saved.
    5. Finally, write a comprehensive summary of your findings. Include references where
       possible.

    Be methodical: search, read, take notes, then summarize.
    """;

var messages = new List<ChatMessage>
{
    new(ChatRole.System, systemPrompt),
    new(ChatRole.User, $"Please research this topic thoroughly: {topic}"),
};

var options = new ChatOptions { Tools = tools };

// Stream the final response so the user sees output incrementally
await foreach (var update in chatClient.GetStreamingResponseAsync(messages, options))
{
    if (update.Role == ChatRole.Assistant)
        Console.Write(update.Text);
}

Console.WriteLine("\n\n📝 Notes collected during research:");
Console.WriteLine(new string('─', 50));
foreach (var note in notebook.Notes)
{
    Console.WriteLine($"  • {note}");
}

return 0;

