// Web Search Tool – uses Bing search via HTML scraping
// ═══════════════════════════════════════════════════════════════════════════
static class WebSearchTool
{
    private static readonly HttpClient Http = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "Mozilla/5.0 (compatible; ResearchAgent/1.0)" },
            { "Accept-Language", "en-US,en;q=0.9" },
        },
        Timeout = TimeSpan.FromSeconds(15),
    };

    [Description("Search the web for a query and return a list of result snippets with URLs.")]
    public static async Task<string> SearchWeb(
        [Description("The search query string")] string query)
    {
        Console.WriteLine($"  🌐 Searching: \"{query}\"");
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";
            var html = await Http.GetStringAsync(url);

            var results = ParseDuckDuckGoResults(html);
            if (results.Count == 0)
                return "No search results found.";

            return JsonSerializer.Serialize(results.Take(8), new JsonSerializerOptions { WriteIndented = true });
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Fetch the text content of a web page given its URL. Returns the first ~3000 characters of readable text.")]
    public static async Task<string> FetchPage(
        [Description("The full URL of the web page to fetch")] string url)
    {
        Console.WriteLine($"  📄 Fetching: {url}");
        try
        {
            var html = await Http.GetStringAsync(url);
            var text = StripHtml(html);
            return text.Length > 3000 ? text[..3000] + "\n... [truncated]" : text;
        }
        catch (Exception ex)
        {
            return $"Failed to fetch page: {ex.Message}";
        }
    }

    private static List<SearchResult> ParseDuckDuckGoResults(string html)
    {
        var results = new List<SearchResult>();
        var span = html.AsSpan();
        var searchIndex = 0;

        while (results.Count < 10)
        {
            // Find result links with class "result__a"
            var marker = "class=\"result__a\"";
            var pos = html.IndexOf(marker, searchIndex, StringComparison.Ordinal);
            if (pos < 0) break;

            // Extract href
            var hrefStart = html.LastIndexOf("href=\"", pos, Math.Min(pos, 200), StringComparison.Ordinal);
            string? href = null;
            if (hrefStart >= 0)
            {
                hrefStart += 6;
                var hrefEnd = html.IndexOf('"', hrefStart);
                if (hrefEnd > hrefStart)
                    href = html[hrefStart..hrefEnd];
            }

            // Extract title (text inside the <a> tag)
            var titleStart = html.IndexOf('>', pos) + 1;
            var titleEnd = html.IndexOf("</a>", titleStart, StringComparison.Ordinal);
            var title = titleStart > 0 && titleEnd > titleStart
                ? StripHtml(html[titleStart..titleEnd]).Trim()
                : "";

            // Extract snippet from result__snippet class
            var snippetMarker = "class=\"result__snippet\"";
            var snippetPos = html.IndexOf(snippetMarker, pos, StringComparison.Ordinal);
            var snippet = "";
            if (snippetPos >= 0 && snippetPos < pos + 2000)
            {
                var snipStart = html.IndexOf('>', snippetPos) + 1;
                var snipEnd = html.IndexOf("</", snipStart, StringComparison.Ordinal);
                if (snipStart > 0 && snipEnd > snipStart)
                    snippet = StripHtml(html[snipStart..snipEnd]).Trim();
            }

            if (!string.IsNullOrEmpty(title) && !string.IsNullOrEmpty(href))
            {
                // DuckDuckGo wraps URLs in a redirect; extract the actual URL
                if (href.Contains("uddg="))
                {
                    var uddgStart = href.IndexOf("uddg=", StringComparison.Ordinal) + 5;
                    var uddgEnd = href.IndexOf('&', uddgStart);
                    href = Uri.UnescapeDataString(
                        uddgEnd > uddgStart ? href[uddgStart..uddgEnd] : href[uddgStart..]);
                }

                results.Add(new SearchResult(title, href, snippet));
            }

            searchIndex = pos + marker.Length;
        }

        return results;
    }

    private static string StripHtml(string html)
    {
        // Remove script/style blocks, then tags, then collapse whitespace
        var text = System.Text.RegularExpressions.Regex.Replace(
            html, @"<(script|style)[^>]*>[\s\S]*?</\1>", " ", System.Text.RegularExpressions.RegexOptions.IgnoreCase);
        text = System.Text.RegularExpressions.Regex.Replace(text, @"<[^>]+>", " ");
        text = System.Text.RegularExpressions.Regex.Replace(text, @"\s+", " ");
        return System.Net.WebUtility.HtmlDecode(text).Trim();
    }

    private record SearchResult(string Title, string Url, string Snippet);
}

