// Note-Taking Tool – in-memory notebook the agent uses to track findings
// ═══════════════════════════════════════════════════════════════════════════
class Notebook
{
    private readonly List<string> _notes = [];
    public IReadOnlyList<string> Notes => _notes;

    [Description("Save a research note. Use this to record key facts, findings, or quotes discovered during research.")]
    public string SaveNote(
        [Description("The note text to save")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  📝 Note #{_notes.Count} saved");
        return $"Note #{_notes.Count} saved successfully.";
    }

    [Description("Retrieve all saved research notes collected so far.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var result = $"Total notes: {_notes.Count}\n\n";
        for (var i = 0; i < _notes.Count; i++)
            result += $"[{i + 1}] {_notes[i]}\n\n";

        return result;
    }
}

